import { cookies } from "next/headers";
import { db, users } from "@/lib/db";
import { eq } from "drizzle-orm";
import type { User } from "@/lib/db/schema";

const SESSION_COOKIE_NAME = "replit_auth_session";

interface ReplitUser {
  id: string;
  name: string;
  email?: string;
  image?: string;
  teams?: string[];
  roles?: string[];
}

export async function getAuthenticatedUser(): Promise<User | null> {
  try {
    const cookieStore = await cookies();
    const sessionToken = cookieStore.get(SESSION_COOKIE_NAME)?.value;
    
    if (!sessionToken) {
      return null;
    }

    const userId = await getUserIdFromSession(sessionToken);
    if (!userId) {
      return null;
    }

    const [user] = await db.select().from(users).where(eq(users.id, userId));
    return user || null;
  } catch (error) {
    console.error("Error getting authenticated user:", error);
    return null;
  }
}

async function getUserIdFromSession(sessionToken: string): Promise<string | null> {
  try {
    const decoded = JSON.parse(Buffer.from(sessionToken, "base64").toString("utf-8"));
    return decoded.userId || null;
  } catch {
    return null;
  }
}

export async function createSession(replitUser: ReplitUser): Promise<string> {
  const [user] = await db
    .insert(users)
    .values({
      id: replitUser.id,
      email: replitUser.email,
      firstName: replitUser.name?.split(" ")[0],
      lastName: replitUser.name?.split(" ").slice(1).join(" "),
      profileImageUrl: replitUser.image,
    })
    .onConflictDoUpdate({
      target: users.id,
      set: {
        email: replitUser.email,
        firstName: replitUser.name?.split(" ")[0],
        lastName: replitUser.name?.split(" ").slice(1).join(" "),
        profileImageUrl: replitUser.image,
        updatedAt: new Date(),
      },
    })
    .returning();

  const sessionData = {
    userId: user.id,
    createdAt: Date.now(),
  };

  return Buffer.from(JSON.stringify(sessionData)).toString("base64");
}

export async function setSessionCookie(sessionToken: string): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.set(SESSION_COOKIE_NAME, sessionToken, {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 60 * 60 * 24 * 7, // 1 week
    path: "/",
  });
}

export async function clearSessionCookie(): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.delete(SESSION_COOKIE_NAME);
}

export async function requireAuth(): Promise<User> {
  const user = await getAuthenticatedUser();
  if (!user) {
    throw new Error("Authentication required");
  }
  return user;
}
